#include "GardenRelayDevice.h"
namespace Garden {
GardenRelayDevice::GardenRelayDevice(const GardenDeviceOptions& options,const uint8_t* relayPins,uint8_t zoneCount,uint8_t masterChannel):GardenDeviceBase(options),_relayPins(relayPins),_zoneCount(zoneCount),_masterChannel(masterChannel){ if(_zoneCount>MAX_ZONES)_zoneCount=MAX_ZONES; for(uint8_t i=0;i<MAX_ZONES;i++){ _zones[i].channel=i+1; _zones[i].enabled=true; snprintf(_zones[i].name,sizeof(_zones[i].name),"Zone %u",i+1); _runs[i].active=false; _relayStates[i]=false;} _relayStates[MAX_ZONES]=false; }
void GardenRelayDevice::setRelayActiveLevel(bool activeHigh){ _activeHigh=activeHigh; }
void GardenRelayDevice::onDeviceBegin(){ for(uint8_t i=0;i<_zoneCount;i++){ pinMode(_relayPins[i],OUTPUT); writeRelay(i+1,false);} if(_masterChannel>0){ pinMode(_relayPins[_masterChannel-1],OUTPUT); writeRelay(_masterChannel,false);} setupRelayRoutes(); }
void GardenRelayDevice::onDeviceLoop(){ bool changed=false; uint32_t now=millis(); for(uint8_t i=0;i<_zoneCount;i++){ if(!_runs[i].active)continue; if(now-_runs[i].startedMs>=_runs[i].durationMs){ _runs[i].active=false; writeRelay(i+1,false); changed=true; }} if(changed){ updateMaster(); enqueueSimpleEvent("zone.run.completed"); }}
void GardenRelayDevice::setupRelayRoutes(){ server().on("/api/zone/run",HTTP_GET,[this](){handleRunRoute();}); server().on("/api/zone/stop",HTTP_GET,[this](){handleStopRoute();}); server().on("/api/alloff",HTTP_GET,[this](){allOff(); sendOk();}); }
void GardenRelayDevice::handleRunRoute(){ uint8_t zone=server().hasArg("zone")?server().arg("zone").toInt():0; uint32_t seconds=server().hasArg("seconds")?server().arg("seconds").toInt():900; if(!startZone(zone,seconds)){ sendError(400,"bad zone/duration"); return;} sendOk(); }
void GardenRelayDevice::handleStopRoute(){ uint8_t zone=server().hasArg("zone")?server().arg("zone").toInt():0; if(!stopZone(zone)){sendError(400,"bad zone");return;} sendOk(); }
bool GardenRelayDevice::startZone(uint8_t zone,uint32_t durationSeconds){ if(zone<1||zone>_zoneCount||durationSeconds==0)return false; uint8_t idx=zone-1; if(!_zones[idx].enabled)return false; _runs[idx].active=true; _runs[idx].startedMs=millis(); _runs[idx].durationMs=durationSeconds*1000UL; writeRelay(zone,true); updateMaster(); enqueueSimpleEvent("zone.run.started"); return true; }
bool GardenRelayDevice::stopZone(uint8_t zone){ if(zone<1||zone>_zoneCount)return false; uint8_t idx=zone-1; _runs[idx].active=false; writeRelay(zone,false); updateMaster(); enqueueSimpleEvent("zone.run.stopped"); return true; }
void GardenRelayDevice::allOff(){ for(uint8_t i=0;i<_zoneCount;i++){ _runs[i].active=false; writeRelay(i+1,false);} if(_masterChannel>0)writeRelay(_masterChannel,false); enqueueSimpleEvent("zone.run.stop_all"); }
void GardenRelayDevice::writeRelay(uint8_t channel,bool on){ if(channel<1)return; uint8_t idx=channel-1; digitalWrite(_relayPins[idx],on==_activeHigh?HIGH:LOW); if(idx<MAX_ZONES+1)_relayStates[idx]=on; }
bool GardenRelayDevice::anyZoneActive() const{ for(uint8_t i=0;i<_zoneCount;i++)if(_runs[i].active)return true; return false; }
void GardenRelayDevice::updateMaster(){ if(_masterChannel>0)writeRelay(_masterChannel,anyZoneActive()); }
void GardenRelayDevice::appendCapabilities(JsonArray capabilities){ capabilities.add("relay.zone_control"); capabilities.add("relay.master_valve"); capabilities.add("event.publisher"); }
void GardenRelayDevice::appendDeviceState(JsonObject state){ state["zoneCount"]=_zoneCount; state["masterChannel"]=_masterChannel; state["masterOn"]=_masterChannel>0?_relayStates[_masterChannel-1]:false; JsonArray zones=state["zones"].to<JsonArray>(); for(uint8_t i=0;i<_zoneCount;i++){ JsonObject z=zones.add<JsonObject>(); z["zone"]=i+1; z["channel"]=_zones[i].channel; z["name"]=_zones[i].name; z["enabled"]=_zones[i].enabled; z["relayOn"]=_relayStates[i]; z["active"]=_runs[i].active; if(_runs[i].active){ uint32_t elapsed=millis()-_runs[i].startedMs; uint32_t rem=_runs[i].durationMs>elapsed?_runs[i].durationMs-elapsed:0; z["remainingSeconds"]=(rem+999UL)/1000UL; } } }
void GardenRelayDevice::appendDeviceConfig(JsonObject config){ config["zoneCount"]=_zoneCount; config["masterChannel"]=_masterChannel; JsonArray zones=config["zones"].to<JsonArray>(); for(uint8_t i=0;i<_zoneCount;i++){ JsonObject z=zones.add<JsonObject>(); z["zone"]=i+1; z["channel"]=_zones[i].channel; z["name"]=_zones[i].name; z["enabled"]=_zones[i].enabled; }}
bool GardenRelayDevice::applyDeviceConfig(JsonObjectConst config){ if(config["zones"].is<JsonArrayConst>()){ for(JsonObjectConst z: config["zones"].as<JsonArrayConst>()){ int zone=z["zone"]|0; if(zone<1||zone>_zoneCount)continue; uint8_t idx=zone-1; if(z["name"].is<const char*>())strlcpy(_zones[idx].name,z["name"],sizeof(_zones[idx].name)); if(z["enabled"].is<bool>())_zones[idx].enabled=z["enabled"]; }} return true; }
bool GardenRelayDevice::handleDeviceMessage(const String& type,JsonObjectConst message,JsonObjectConst payload){ (void)message; if(type=="zone.run.start"){ uint32_t duration=payload["durationSeconds"]|900; if(payload["zone"].is<int>())return startZone(payload["zone"],duration); if(payload["zones"].is<JsonArrayConst>()){ bool ok=true; for(JsonVariantConst v:payload["zones"].as<JsonArrayConst>())ok=startZone(v.as<int>(),duration)&&ok; return ok; }} if(type=="zone.run.stop"){ if(payload["zone"].is<int>())return stopZone(payload["zone"]); } if(type=="zone.run.stop_all"){ allOff(); return true;} return false; }
} // namespace Garden
